class Trie:
    def __init__(self):
        self.trie = {};

    def insert(self, s: str) -> bool:
        if s in self.trie:
            return False
        index = 0
        for c in s:
            if c not in self.trie[index]:
                self.trie[index][c] = {}
            index = self.trie[index][c]        self.trie[index]['$'] = True
        return True

solutions.cpp:
class Trie {
public:
    bool insert(string s) {
        if (trie.count(s) != 0) {
            return false;
        }
        int index = 0;
        for (char c : s) {
            if (trie[index].count(c) == 0) {
                trie[index][c] = {};
            }
            index = trie[index][c];
        }
        trie[index]['$'] = true;
        return true;
    }
};
